//! Replay of frozen chain-query RPC handler vectors generated by an
//! in-package dump test running inside dcrd's internal/rpcserver
//! package at release-v2.1.5: 41 cases across getbestblock,
//! getbestblockhash, getblockcount, getcoinsupply, getdifficulty,
//! getchaintips, getblockhash, getblockchaininfo, getheaders,
//! getblockheader, and getblock (with dcrd's own mainnet block 432100
//! as the fixture), each carrying the marshalled request params
//! (parsed here through the ported dcrjson pipeline), the mock chain
//! seam facts, and the marshalled result or the exact error code and
//! message.

// Index arithmetic over pinned vector rows.
#![allow(clippy::arithmetic_side_effects)]

use dcroxide_chaincfg::mainnet_params;
use dcroxide_chainhash::Hash;
